#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

__kernel void bpnn_layerforward_ocl(__global float* input_units,
                                   __global float* hidden_units,
                                   __global float* input_weights,
                                   __global float* hidden_partial_sum,
                                   __local float* lsum,
                                   __local float* lweights,
                                   const int input_n,
                                   const int hidden_n)
{
    int tx = get_local_id(0);
    int ty = get_local_id(1);
    int bx = get_group_id(0);
    int by = get_group_id(1);

    int row = bx * BLOCK_SIZE + tx; // input index
    int col = by * BLOCK_SIZE + ty; // hidden index

    int input_size = input_n + 1;
    int hidden_size = hidden_n + 1;

    // Each work-item computes partial sum for one element of the output matrix block
    float sum = 0.0f;

    // Load input units into local memory
    if (ty == 0 && row < input_size) {
        lsum[tx] = input_units[row];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    // Loop over input units in chunks of BLOCK_SIZE
    for (int i = 0; i < input_size; i += BLOCK_SIZE) {
        int idx = i + tx;
        if (idx < input_size && col < hidden_size) {
            // Load weights into local memory
            lweights[tx * BLOCK_SIZE + ty] = input_weights[idx * hidden_size + col];
        } else {
            lweights[tx * BLOCK_SIZE + ty] = 0.0f;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        // Compute partial sum
        for (int k = 0; k < BLOCK_SIZE; k++) {
            if ((i + k) < input_size) {
                sum += lweights[k * BLOCK_SIZE + ty] * lsum[k];
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write partial sums to global memory for reduction
    int partial_sum_index = bx * hidden_n + col - 1;
    if (row < input_size && col > 0 && col <= hidden_n) {
        hidden_partial_sum[partial_sum_index] = sum;
    }
    // No output written for col == 0 (bias unit)
}

__kernel void bpnn_adjust_weights_ocl(__global float* delta,
                                     const int ndelta,
                                     __global float* ly,
                                     const int nly,
                                     __global float* w,
                                     __global float* oldw)
{
    int j = get_global_id(0) + 1; // delta index (1-based)
    int k = get_global_id(1);     // ly index (0-based)

    if (j <= ndelta && k <= nly) {
        int idx = k * (ndelta + 1) + j;
        float new_dw = ETA * delta[j] * ly[k] + MOMENTUM * oldw[idx];
        w[idx] += new_dw;
        oldw[idx] = new_dw;
    }
}
